        EstimatedDelivery = EstimatedDelivery,
        RecipientName = RecipientName,
        Description = Description
    };
}

using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentDbService(IDbContextFactory<ApplicationDbContext> contextFactory) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        await using var context = await contextFactory.CreateDbContextAsync();
        return await context.Shipments
            .OrderByDescending(s => s.CreatedDate)
            .Select(s => s.ToDto())
            .ToListAsync();
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        await using var context = await contextFactory.CreateDbContextAsync();
        var shipment = await context.Shipments
            .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return shipment?.ToDto();
    }

    public async Task<bool> UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        await using var context = await contextFactory.CreateDbContextAsync();
        var shipment = await context.Shipments.FindAsync(id);
        if (shipment is null)
            return false;

        shipment.Status = status;
        await context.SaveChangesAsync();
        return true;
    }
}

using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public static class SeedData
{
    public static async Task InitializeAsync(IServiceProvider services)
    {
        using var scope = services.CreateScope();
        var context = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
        await context.Database.MigrateAsync();

        var roleManager = scope.ServiceProvider.GetRequiredService<RoleManager<IdentityRole>>();
        if (!await roleManager.RoleExistsAsync("Dispatcher"))
            await roleManager.CreateAsync(new IdentityRole("Dispatcher"));
        if (!await roleManager.RoleExistsAsync("Customer"))
            await roleManager.CreateAsync(new IdentityRole("Customer"));

        if (!await context.Shipments.AnyAsync())
        {
            var now = DateTime.UtcNow;
            context.Shipments.AddRange(
                new Shipment
                {
                    TrackingNumber = "TRK-100001",
                    Origin = "New York, NY",
                    Destination = "Los Angeles, CA",
                    Status = ShipmentStatus.InTransit,
                    CreatedDate = now.AddDays(-3),
                    EstimatedDelivery = now.AddDays(2),
                    RecipientName = "Alice Johnson",
                    Description = "Electronics — 2 boxes"
                },
                new Shipment
                {
                    TrackingNumber = "TRK-100002",
                    Origin = "Chicago, IL",
                    Destination = "Miami, FL",
                    Status = ShipmentStatus.Pending,
                    CreatedDate = now.AddDays(-1),
                    EstimatedDelivery = now.AddDays(5),
                    RecipientName = "Bob Smith",
                    Description = "Furniture — 1 crate"
                },
                new Shipment
                {
                    TrackingNumber = "TRK-100003",
                    Origin = "Seattle, WA",
                    Destination = "Denver, CO",
                    Status = ShipmentStatus.OutForDelivery,
                    CreatedDate = now.AddDays(-5),
                    EstimatedDelivery = now,
                    RecipientName = "Carol Williams",
                    Description = "Medical supplies"
                },
                new Shipment
                {
                    TrackingNumber = "TRK-100004",
                    Origin = "Houston, TX",
                    Destination = "Phoenix, AZ",
                    Status = ShipmentStatus.Delivered,
                    CreatedDate = now.AddDays(-7),
                    EstimatedDelivery = now.AddDays(-2),
                    RecipientName = "David Lee",
                    Description = "Auto parts — 3 pallets"
                },
                new Shipment
                {
                    TrackingNumber = "TRK-100005",
                    Origin = "Boston, MA",
                    Destination = "Atlanta, GA",
                    Status = ShipmentStatus.PickedUp,
                    CreatedDate = now,
                    EstimatedDelivery = now.AddDays(4),
                    RecipientName = "Eve Martinez",
                    Description = "Clothing shipment"
                }
            );
            await context.SaveChangesAsync();
        }
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments");

        group.MapGet("/", async (ApplicationDbContext db) =>
        {
            var shipments = await db.Shipments
                .OrderByDescending(s => s.CreatedDate)
                .Select(s => s.ToDto())
                .ToListAsync();
            return Results.Ok(shipments);
        }).RequireAuthorization();

        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments
                .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            return shipment is not null ? Results.Ok(shipment.ToDto()) : Results.NotFound();
        }).RequireAuthorization();

        group.MapPut("/{id:int}/status", async (int id, [FromBody] UpdateShipmentStatusRequest request, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null)
                return Results.NotFound();

            shipment.Status = request.Status;
            await db.SaveChangesAsync();
            return Results.Ok(shipment.ToDto());
        }).RequireAuthorization("DispatcherPolicy");
    }
}

