@page "/dispatcher"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize(Roles = "Dispatcher")]
@rendermode InteractiveAuto
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h2>Dispatcher Dashboard</h2>
<p class="text-muted">Manage all shipments, filter by status, and update shipment progress.</p>

<div class="row mb-3">
    <div class="col-md-4">
        <label class="form-label">Filter by status</label>
        <select class="form-select" @bind="statusFilter">
            <option value="">All</option>
            @foreach (var s in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@s">@s</option>
            }
        </select>
    </div>
    <div class="col-md-4">
        <label class="form-label">Search</label>
        <input class="form-control" placeholder="Tracking # or recipient" @bind="searchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-4 d-flex align-items-end">
        <button class="btn btn-primary" @onclick="LoadShipments">
            <span class="bi bi-arrow-clockwise"></span> Refresh
        </button>
    </div>
</div>

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!FilteredShipments.Any())
{
    <div class="alert alert-info">No shipments match the current filters.</div>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Recipient</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in FilteredShipments)
                {
                    <tr>
                        <td><strong>@shipment.TrackingNumber</strong></td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td>@shipment.RecipientName</td>
                        <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></td>
                        <td>@(shipment.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</td>
                        <td>
                            <select class="form-select form-select-sm" style="width:auto;display:inline-block"
                                    value="@shipment.Status"
                                    @onchange="e => UpdateStatus(shipment, e)">
                                @foreach (var s in Enum.GetValues<ShipmentStatus>())
                                {
                                    <option value="@s" selected="@(s == shipment.Status)">@s</option>
                                }
                            </select>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
    <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
}

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger mt-2">@errorMessage</div>
}

@code {
    private List<ShipmentDto>? shipments;
    private string statusFilter = "";
    private string searchTerm = "";
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        errorMessage = null;
        try
        {
            shipments = await ShipmentService.GetAllShipmentsAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load shipments: {ex.Message}";
        }
    }

    private IEnumerable<ShipmentDto> FilteredShipments =>
        (shipments ?? []).Where(s =>
        {
            if (!string.IsNullOrEmpty(statusFilter) && Enum.TryParse<ShipmentStatus>(statusFilter, out var f) && s.Status != f)
                return false;
            if (!string.IsNullOrEmpty(searchTerm) &&
                !s.TrackingNumber.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) &&
                !s.RecipientName.Contains(searchTerm, StringComparison.OrdinalIgnoreCase))
                return false;
            return true;
        });

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            errorMessage = null;
            var success = await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            if (success)
                shipment.Status = newStatus;
            else
                errorMessage = $"Failed to update status for {shipment.TrackingNumber}.";
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@rendermode InteractiveAuto
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h2>Track Your Shipment</h2>
<p class="text-muted">Enter your tracking number to see the current status and estimated delivery.</p>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input class="form-control" placeholder="e.g. TRK-100001" @bind="trackingNumber"
                   @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="Search" disabled="@isSearching">
                @if (isSearching)
                {
                    <span class="spinner-border spinner-border-sm" role="status"></span>
                    <span> Searching...</span>
                }
                else
                {
                    <span>Track</span>
                }
            </button>
        </div>
    </div>
</div>

@if (hasSearched && shipment is null && !isSearching)
{
    <div class="alert alert-warning">
        No shipment found for tracking number "<strong>@searchedNumber</strong>".
        Please check the number and try again.
    </div>
}

@if (shipment is not null)
{
    <div class="card">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@shipment.TrackingNumber</h5>
            <span class="badge @GetStatusBadgeClass(shipment.Status) fs-6">@FormatStatus(shipment.Status)</span>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Origin</dt>
                        <dd>@shipment.Origin</dd>
                        <dt>Destination</dt>
                        <dd>@shipment.Destination</dd>
                        <dt>Recipient</dt>
                        <dd>@shipment.RecipientName</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Description</dt>
                        <dd>@shipment.Description</dd>
                        <dt>Shipped On</dt>
                        <dd>@shipment.CreatedDate.ToString("MMMM dd, yyyy")</dd>
                        <dt>Estimated Delivery</dt>
                        <dd>
                            @if (shipment.EstimatedDelivery.HasValue)
                            {
                                <strong>@shipment.EstimatedDelivery.Value.ToString("MMMM dd, yyyy")</strong>
                                @if (shipment.Status != ShipmentStatus.Delivered && shipment.Status != ShipmentStatus.Cancelled)
                                {
                                    var daysLeft = (shipment.EstimatedDelivery.Value.Date - DateTime.UtcNow.Date).Days;
                                    if (daysLeft > 0)
                                    {
                                        <span class="text-muted"> (@daysLeft day@(daysLeft != 1 ? "s" : "") away)</span>
                                    }
                                    else if (daysLeft == 0)
                                    {
                                        <span class="text-success"> (arriving today)</span>
                                    }
                                    else
                                    {
                                        <span class="text-danger"> (delayed)</span>
                                    }
                                }
                            }
                            else
                            {
                                <span>—</span>
                            }
                        </dd>
                    </dl>
                </div>
            </div>

            <!-- Status progress bar -->
            <h6 class="mt-3">Shipment Progress</h6>
            <div class="d-flex justify-content-between mb-1">
                @foreach (var step in progressSteps)
                {
                    var reached = GetProgressIndex(shipment.Status) >= GetProgressIndex(step);
                    <div class="text-center flex-fill">
                        <div class="rounded-circle mx-auto mb-1 @(reached ? "bg-success" : "bg-light border")"
                             style="width:24px;height:24px"></div>
                        <small class="@(reached ? "fw-bold" : "text-muted")">@FormatStatus(step)</small>
                    </div>
                }
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = "";
    private string searchedNumber = "";
    private ShipmentDto? shipment;
    private bool hasSearched;
    private bool isSearching;

    private static readonly ShipmentStatus[] progressSteps =
    [
        ShipmentStatus.Pending,
        ShipmentStatus.PickedUp,
        ShipmentStatus.InTransit,
        ShipmentStatus.OutForDelivery,
        ShipmentStatus.Delivered
    ];

    private async Task Search()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber))
            return;

        isSearching = true;
        searchedNumber = trackingNumber.Trim();
        shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(searchedNumber);
        hasSearched = true;
        isSearching = false;
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await Search();
    }

    private static int GetProgressIndex(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 0,
        ShipmentStatus.PickedUp => 1,
        ShipmentStatus.InTransit => 2,
        ShipmentStatus.OutForDelivery => 3,
        ShipmentStatus.Delivered => 4,
        ShipmentStatus.Cancelled => -1,
        _ => -1
    };

    private static string FormatStatus(ShipmentStatus status) => status switch
    {
        ShipmentStatus.InTransit => "In Transit",
        ShipmentStatus.OutForDelivery => "Out for Delivery",
        ShipmentStatus.PickedUp => "Picked Up",
        _ => status.ToString()
    };

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

