                                        <span class="text-success"> (arriving today)</span>
                                    }
                                    else
                                    {
                                        <span class="text-danger"> (delayed)</span>
                                    }
                                }
                            }
                            else
                            {
                                <span>—</span>
                            }
                        </dd>
                    </dl>
                </div>
            </div>

            <!-- Status progress bar -->
            <h6 class="mt-3">Shipment Progress</h6>
            <div class="d-flex justify-content-between mb-1">
                @foreach (var step in progressSteps)
                {
                    var reached = GetProgressIndex(shipment.Status) >= GetProgressIndex(step);
                    <div class="text-center flex-fill">
                        <div class="rounded-circle mx-auto mb-1 @(reached ? "bg-success" : "bg-light border")"
                             style="width:24px;height:24px"></div>
                        <small class="@(reached ? "fw-bold" : "text-muted")">@FormatStatus(step)</small>
                    </div>
                }
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = "";
    private string searchedNumber = "";
    private ShipmentDto? shipment;
    private bool hasSearched;
    private bool isSearching;

    private static readonly ShipmentStatus[] progressSteps =
    [
        ShipmentStatus.Pending,
        ShipmentStatus.PickedUp,
        ShipmentStatus.InTransit,
        ShipmentStatus.OutForDelivery,
        ShipmentStatus.Delivered
    ];

    private async Task Search()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber))
            return;

        isSearching = true;
        searchedNumber = trackingNumber.Trim();
        shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(searchedNumber);
        hasSearched = true;
        isSearching = false;
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await Search();
    }

    private static int GetProgressIndex(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 0,
        ShipmentStatus.PickedUp => 1,
        ShipmentStatus.InTransit => 2,
        ShipmentStatus.OutForDelivery => 3,
        ShipmentStatus.Delivered => 4,
        ShipmentStatus.Cancelled => -1,
        _ => -1
    };

    private static string FormatStatus(ShipmentStatus status) => status switch
    {
        ShipmentStatus.InTransit => "In Transit",
        ShipmentStatus.OutForDelivery => "Out for Delivery",
        ShipmentStatus.PickedUp => "Picked Up",
        _ => status.ToString()
    };

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

